import { AlertCircle, Loader2 } from 'lucide-react';

import { HarmonyDialog } from '@/components/ui/harmony-dialog';
import { PermissionGate } from '@/components/shared/PermissionGate';
import { PERMISSIONS } from '@/constants/permissions';
import CustomQuill from '@/components/ui/CustomQuill';
import type { Role } from '@/types/role';
import { Button } from '@/shadcn/components/ui/button';
import { Alert, AlertDescription } from '@/shadcn/components/ui/alert';

interface RoleFormDialogProps {
  open: boolean;
  onClose: () => void;
  editingRole: Role | null;
  formData: { name: string; description: string };
  onFormDataChange: (data: { name: string; description: string }) => void;
  error: string | null;
  isSubmitting: boolean;
  onSubmit: (e: React.FormEvent) => void;
}

export function RoleFormDialog({
  open,
  onClose,
  editingRole,
  formData,
  onFormDataChange,
  error,
  isSubmitting,
  onSubmit,
}: RoleFormDialogProps) {
  return (
    <HarmonyDialog
      open={open}
      onOpenChange={(o) => { if (!o) onClose(); }}
      title={editingRole ? 'Update Role' : 'Create Role'}
      footerChildren={
        <div className="flex justify-end gap-3 w-full">
          <Button type="button" variant="outline" onClick={onClose} disabled={isSubmitting}>
            Cancel
          </Button>
          <PermissionGate
            permission={editingRole ? PERMISSIONS.Role.Update : PERMISSIONS.Role.Create}
            mode="disable"
          >
            <Button type="submit" form="role-form" disabled={isSubmitting}>
              {isSubmitting ? <Loader2 className="animate-spin" size={16} /> : null}
              {editingRole ? 'Update Role' : 'Create Role'}
            </Button>
          </PermissionGate>
        </div>
      }
    >
      <form id="role-form" onSubmit={onSubmit} className="space-y-5">
        {error && (
          <Alert variant="destructive">
            <AlertCircle />
            <AlertDescription>{error}</AlertDescription>
          </Alert>
        )}
        <div>
          <label className="form-label">Role Name</label>
          <input
            required
            value={formData.name}
            onChange={e => onFormDataChange({ ...formData, name: e.target.value })}
            className="form-input"
            placeholder="e.g. Finance Manager"
          />
        </div>
        <div>
          <label className="form-label">Description</label>
          <div className="border border-border rounded-xl overflow-hidden focus-within:border-primary transition-all ring-primary/20 focus-within:ring-2">
            <CustomQuill
              value={formData.description}
              onChange={val => onFormDataChange({ ...formData, description: val })}
              placeholder="What can this role do?"
            />
          </div>
        </div>
      </form>
    </HarmonyDialog>
  );
}
