import { useState, useEffect } from 'react';

import { useNavigate } from 'react-router-dom';
import { Shield, Plus, Check } from 'lucide-react';
import { roleService as accountService } from '@/api/auth/roleService';
import { getApiErrorMessage } from '@/api/app/apiError';
import { useQuery } from '@tanstack/react-query';

import { PermissionGate } from '@/components/shared/PermissionGate';
import { PERMISSIONS } from '@/constants/permissions';
import { HarmonyAlertDialog } from '@/components/ui/harmony-alert-dialog';
import { RoleFormDialog } from '@/features/roles/components/RoleFormDialog';
import { Button } from '@/shadcn/components/ui/button';

import type { Role } from '@/types/role';

const ManageRoles = () => {
  const navigate = useNavigate();
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingRole, setEditingRole] = useState<Role | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);
  const [refreshKey, setRefreshKey] = useState(0);
  const [roleToDelete, setRoleToDelete] = useState<Role | null>(null);
  const [isDeleting, setIsDeleting] = useState(false);

  // Form State
  const [formData, setFormData] = useState({ name: '', description: '' });

  const { data: roles = [], isLoading: rolesLoading } = useQuery<Role[]>({
    queryKey: ['roles', refreshKey],
    queryFn: () => accountService.getRoles()
  });

  useEffect(() => {
    if (successMessage) {
      const timer = setTimeout(() => setSuccessMessage(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [successMessage]);

  const handleOpenModal = (role: Role | null = null) => {
    setError(null);
    if (role) {
      setEditingRole(role);
      setFormData({ name: role.name, description: role.description || '' });
    } else {
      setEditingRole(null);
      setFormData({ name: '', description: '' });
    }
    setIsModalOpen(true);
  };

  const handleSubmitRole = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      setIsSubmitting(true);
      setError(null);
      if (editingRole) {
        await accountService.updateRole(editingRole.id, formData);
        setSuccessMessage('Role updated successfully.');
      } else {
        await accountService.createRole(formData);
        setSuccessMessage('Role created successfully.');
      }
      setIsModalOpen(false);
      setRefreshKey(prev => prev + 1);
    } catch (err) {
      setError(getApiErrorMessage(err));
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDeleteRole = (role: Role) => {
    setRoleToDelete(role);
  };

  const confirmDelete = async () => {
    if (!roleToDelete) return;
    try {
      setIsDeleting(true);
      await accountService.deleteRole(roleToDelete.id);
      setSuccessMessage('Role deleted successfully.');
      setRefreshKey(prev => prev + 1);
      setRoleToDelete(null);
    } catch (err) {
      setError(getApiErrorMessage(err));
    } finally {
      setIsDeleting(false);
    }
  };

  return (
    <div className="page-wrapper">
      <div className="max-w-6xl mx-auto">
        
        {/* Alerts */}
        {successMessage && (
          <div className="mb-6 flex items-center gap-2 rounded-lg border border-primary/20 bg-primary/10 px-4 py-3 text-sm text-primary">
            <Check size={16} />
            <span>{successMessage}</span>
          </div>
        )}

        {/* Header */}
        <div className="page-header">
          <div>
            <h1 className="page-title">Role Management</h1>
            <p className="page-subtitle">Define and configure security roles and permissions</p>
          </div>
          <PermissionGate permission={PERMISSIONS.Role.Create} mode="disable">
            <Button onClick={() => handleOpenModal()}>
              <Plus size={16} /> Create Role
            </Button>
          </PermissionGate>
        </div>

        {/* Roles List */}
        <div className="section-card overflow-hidden">
          {rolesLoading ? (
            <div className="py-12 text-center text-muted-foreground text-sm">Loading roles...</div>
          ) : (
            <table className="data-table">
              <thead>
                <tr>
                  <th>Role</th>
                  <th>Description</th>
                  <th className="text-right">Actions</th>
                </tr>
              </thead>
              <tbody>
                {roles.map(role => (
                  <tr key={role.id}>
                    <td>
                      <div className="flex items-center gap-3">
                        <div className="p-2 bg-primary/10 rounded-lg text-primary border border-primary/20">
                          <Shield size={16} />
                        </div>
                        <span className="font-semibold text-foreground">{role.name}</span>
                      </div>
                    </td>
                    <td>
                      <div
                        className="text-muted-foreground text-sm line-clamp-1 max-w-sm"
                        dangerouslySetInnerHTML={{ __html: role.description || "No description provided." }}
                      />
                    </td>
                    <td className="text-right">
                      <div className="flex items-center justify-end gap-3">
                        <PermissionGate permission={PERMISSIONS.RolePermission.Read} mode="disable">
                          <Button variant="link" className="h-auto p-0" onClick={() => navigate(`/roles/${role.id}/configure`)}>
                            Configure
                          </Button>
                        </PermissionGate>
                        <PermissionGate permission={PERMISSIONS.Role.Update} mode="disable">
                          <Button variant="link" className="h-auto p-0" onClick={() => handleOpenModal(role)}>Edit</Button>
                        </PermissionGate>
                        <PermissionGate permission={PERMISSIONS.Role.Delete} mode="disable">
                          <Button variant="link" className="h-auto p-0 text-destructive hover:text-destructive" onClick={() => handleDeleteRole(role)}>Delete</Button>
                        </PermissionGate>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>

        <RoleFormDialog
          open={isModalOpen}
          onClose={() => setIsModalOpen(false)}
          editingRole={editingRole}
          formData={formData}
          onFormDataChange={setFormData}
          error={error}
          isSubmitting={isSubmitting}
          onSubmit={handleSubmitRole}
        />
        {roleToDelete && (
          <HarmonyAlertDialog
            open={!!roleToDelete}
            onOpenChange={(open) => { if (!open) setRoleToDelete(null); }}
            variant="danger"
            title="Delete Security Role"
            description={`This will permanently remove the "${roleToDelete.name}" role. This action cannot be undone.`}
            actionLabel="Delete Role"
            onAction={confirmDelete}
            isActioning={isDeleting}
          />
        )}
      </div>
    </div>
  );
};

export default ManageRoles;
